{
  "name": "starter",
  "version": "0.1.0",
  "private": true,
  "type": "module",
  "scripts": {
    "dev": "flink-reactor dev",
    "synth": "flink-reactor synth",
    "validate": "flink-reactor validate",
    "test": "vitest run",
    "test:watch": "vitest"
  },
  "dependencies": {
    "@flink-reactor/dsl": "^0.1.0"
  },
  "devDependencies": {
    "typescript": "^5.7.0",
    "vitest": "^3.0.0"
  }
}

{
  "compilerOptions": {
    "target": "ES2022",
    "module": "ESNext",
    "moduleResolution": "bundler",
    "lib": [
      "ES2022"
    ],
    "strict": true,
    "esModuleInterop": true,
    "skipLibCheck": true,
    "forceConsistentCasingInFileNames": true,
    "resolveJsonModule": true,
    "jsx": "react-jsx",
    "jsxImportSource": "@flink-reactor/dsl",
    "baseUrl": ".",
    "paths": {
      "@/*": [
        "./*"
      ]
    }
  },
  "include": [
    "pipelines/**/*",
    "schemas/**/*",
    "patterns/**/*"
  ]
}

import { fileURLToPath } from 'node:url'
import { defineConfig } from 'vitest/config'

export default defineConfig({
  resolve: {
    alias: {
      '@': fileURLToPath(new URL('.', import.meta.url)),
    },
  },
})

import { defineConfig } from '@flink-reactor/dsl'

export default defineConfig({
  flink: { version: '2.3' },

  // Infra services this project depends on. Empty here — `fr cluster up`
  // and `fr sim up` will start only the always-on services (Flink core,
  // SQL gateway, SeaweedFS). Add services as your pipelines need them, e.g.
  // `services: { kafka: {} }` to enable Kafka.
  services: {},

  // `sources` lets `fr schema generate` emit typed `schemas/*.ts` modules by
  // introspecting a live Kafka Schema Registry or Postgres — no hand-writing.
  // Uncomment and point at your source once you add a pipeline, e.g.:
  //   sources: {
  //     orders: { type: 'kafka', topic: 'orders' },
  //     // customers: { type: 'postgres', table: 'public.customers' },
  //   },

  environments: {
    development: {
      cluster: { url: 'http://localhost:8081' },
      dashboard: { mockMode: true },
      pipelines: { '*': { parallelism: 1 } },
    },
    production: {
      cluster: { url: 'https://flink-prod:8081' },
      kubernetes: { namespace: 'flink-prod' },
      pipelines: { '*': { parallelism: 4 } },
    },
  },
})

import { defineConfig } from '@flink-reactor/dsl';

export default defineConfig({
  flink: { version: '2.3' },

  // Kafka-only template: `fr cluster up` and `fr sim up` start Flink + Kafka.
  // No Postgres, Iceberg, or Fluss. `schemaRegistryUrl` is the published host
  // port of the bundled registry — read by `fr schema generate`, not by the
  // runtime connectors (which use `format="debezium-json"`, registry-free).
  services: { kafka: { bootstrapServers: 'kafka:9092', schemaRegistryUrl: 'http://localhost:8082' } },

  // `sources` powers `fr schema generate`: introspect the topic's row schema
  // from the Schema Registry and emit `schemas/products.ts`. `fr cluster up`
  // registers this topic's schema automatically, so `fr schema generate
  // products` works out of the box. (JSON Schema has no INT/BIGINT split, so
  // regenerated integers come back as BIGINT — narrow them if you want INT.)
  sources: {
    products: { type: 'kafka', topic: 'cdc.inventory.products' },
  },

  environments: {
    // Docker-compose by default — matches the platform docs' recommended
    // local lane. Override with `fr up --runtime=minikube` to exercise the
    // Kubernetes lane without editing config.
    development: {
      runtime: 'docker',
      supportedRuntimes: ['docker', 'minikube'],
      cluster:    { url: 'http://localhost:8081' },
      sqlGateway: { url: 'http://localhost:8083' },   // used when runtime=docker
      kubectl:    { context: 'minikube' },             // used when runtime=minikube
      sim: {
        init: {
          kafka: {
            topics: ['in-stock-products'],
            catalogs: [{
              name: 'cdc',
              tables: [{
                table: 'inventory_products',
                topic: 'cdc.inventory.products',
                format: 'debezium-json',
                columns: {
                  id: 'INT',
                  name: 'STRING',
                  category: 'STRING',
                  price: 'DOUBLE',
                  quantity: 'INT',
                },
                primaryKey: ['id'],
              }],
            }],
          },
        },
      },
      pipelines: { '*': { parallelism: 1 } },
    },

    // CI / integration tests — full K8s lane on minikube.
    test: {
      runtime: 'minikube',
      kubectl:    { context: 'minikube' },
      kubernetes: { namespace: 'flink-test' },
      pipelines:  { '*': { parallelism: 1 } },
    },

    // Pre-prod validation on a remote cluster. `kubectl.context` is required —
    // no sensible default exists.
    staging: {
      runtime: 'kubernetes',
      kubectl:    { context: 'staging' },
      kubernetes: { namespace: 'flink-staging' },
      pipelines:  { '*': { parallelism: 2 } },
    },

    production: {
      runtime: 'kubernetes',
      kubectl:    { context: 'production' },
      kubernetes: { namespace: 'flink-prod' },
      pipelines:  { '*': { parallelism: 4 } },
    },
  },
});

import { Schema, Field } from '@flink-reactor/dsl';

export const ProductsSchema = Schema({
  fields: {
    id: Field.INT(),
    name: Field.STRING(),
    category: Field.STRING(),
    price: Field.DOUBLE(),
    quantity: Field.INT(),
  },
  primaryKey: { columns: ['id'] },
});

import { Pipeline, KafkaSource, KafkaSink, Filter } from '@flink-reactor/dsl';
import { ProductsSchema } from '@/schemas/products';

export default (
  <Pipeline name="hello-world">
    <KafkaSource
      topic="cdc.inventory.products"
      schema={ProductsSchema}
      format="debezium-json"
      bootstrapServers="kafka:9092"
      consumerGroup="hello-world"
    />
    <Filter condition="quantity > 0" />
    <KafkaSink
      topic="in-stock-products"
      bootstrapServers="kafka:9092"
    />
  </Pipeline>
);

import { beforeEach, describe, expect, it } from 'vitest'
import {
  type ConstructNode,
  resetNodeIdCounter,
  synthesizeApp,
} from '@flink-reactor/dsl'
import pipeline from '../../pipelines/hello-world/index.js'

function synth(node: ConstructNode): string {
  const result = synthesizeApp({ name: 'hello-world', children: [node] })
  return result.pipelines[0].sql.sql
}

describe('hello-world pipeline', () => {
  beforeEach(() => {
    resetNodeIdCounter()
  })

  it('synthesizes stable SQL', () => {
    const sql = synth(pipeline)

    expect(sql).toMatchSnapshot()

    expect(sql).toMatch(/cdc\.inventory\.products/)
    expect(sql).toMatch(/quantity > 0/)
    expect(sql).toMatch(/debezium-json/)
  })
})

