import { fileURLToPath } from 'node:url'
import { defineConfig } from 'vitest/config'

export default defineConfig({
  resolve: {
    alias: {
      '@': fileURLToPath(new URL('.', import.meta.url)),
    },
  },
})

import { defineConfig } from '@flink-reactor/dsl'

export default defineConfig({
  flink: { version: '2.3' },

  // Infra services this project depends on. Empty here — `fr cluster up`
  // and `fr sim up` will start only the always-on services (Flink core,
  // SQL gateway, SeaweedFS). Add services as your pipelines need them, e.g.
  // `services: { kafka: {} }` to enable Kafka.
  services: {},

  // `sources` lets `fr schema generate` emit typed `schemas/*.ts` modules by
  // introspecting a live Kafka Schema Registry or Postgres — no hand-writing.
  // Uncomment and point at your source once you add a pipeline, e.g.:
  //   sources: {
  //     orders: { type: 'kafka', topic: 'orders' },
  //     // customers: { type: 'postgres', table: 'public.customers' },
  //   },

  environments: {
    development: {
      cluster: { url: 'http://localhost:8081' },
      dashboard: { mockMode: true },
      pipelines: { '*': { parallelism: 1 } },
    },
    production: {
      cluster: { url: 'https://flink-prod:8081' },
      kubernetes: { namespace: 'flink-prod' },
      pipelines: { '*': { parallelism: 4 } },
    },
  },
})

import { defineConfig } from '@flink-reactor/dsl';

export default defineConfig({
  flink: { version: '2.3' },

  // CDC stream lands in Kafka, lakehouse stores in Iceberg
  // (Lakekeeper-backed Iceberg REST → Postgres pulls in implicitly).
  services: { kafka: { bootstrapServers: 'kafka:9092', schemaRegistryUrl: 'http://localhost:8082' }, iceberg: {} },

  // `sources` powers `fr schema generate`: introspect the CDC topic's row
  // schema from the bundled Schema Registry and re-emit `schemas/orders.ts`.
  // `fr cluster up` registers this topic's row schema automatically, so
  // `fr schema generate orders` works out of the box. The topic is read with
  // `format="debezium-json"` at runtime (registry-free); the registry is
  // consulted only by `schema generate`. (JSON Schema has no DECIMAL, so a
  // regenerated `amount` widens to DOUBLE — restore `DECIMAL(10, 2)` by hand.)
  sources: {
    orders: { type: 'kafka', topic: 'dbserver1.inventory.orders' },
  },

  environments: {
    minikube: {
      cluster: { url: 'http://localhost:8081' },
      sim: {
        init: {
          iceberg: { databases: ['inventory'] },
          kafka: {
            topics: ['dbserver1.inventory.orders'],
            catalogs: [
              {
                name: 'cdc',
                tables: [
                  {
                    table: 'inventory_orders',
                    topic: 'dbserver1.inventory.orders',
                    columns: {
                      orderId: 'BIGINT',
                      customerId: 'BIGINT',
                      product: 'STRING',
                      amount: 'DECIMAL(10, 2)',
                      status: 'STRING',
                      createdAt: 'TIMESTAMP(3)',
                      updatedAt: 'TIMESTAMP(3)',
                    },
                    format: 'debezium-json',
                    primaryKey: ['orderId'],
                  },
                ],
              },
            ],
          },
        },
      },
      pipelines: { '*': { parallelism: 2 } },
    },
    production: {
      cluster: { url: 'https://flink-prod:8081' },
      kubernetes: { namespace: 'flink-prod' },
      pipelines: { '*': { parallelism: 4 } },
    },
  },
});

import { Schema, Field } from '@flink-reactor/dsl';

export const OrdersSchema = Schema({
  fields: {
    orderId: Field.BIGINT(),
    customerId: Field.BIGINT(),
    product: Field.STRING(),
    amount: Field.DECIMAL(10, 2),
    status: Field.STRING(),
    createdAt: Field.TIMESTAMP(3),
    updatedAt: Field.TIMESTAMP(3),
  },
  primaryKey: { columns: ['orderId'] },
});

import { Pipeline, KafkaSource, IcebergCatalog, IcebergSink } from '@flink-reactor/dsl';
import { OrdersSchema } from '@/schemas/orders';

// Iceberg REST catalog backed by SeaweedFS S3 storage
const iceberg = IcebergCatalog({
  name: 'lakehouse',
  catalogType: 'rest',
  uri: 'http://lakekeeper.localtest.me:8181/catalog',
  warehouse: 'flink-warehouse',
});

export default (
  <Pipeline
    name="cdc-to-lakehouse"
    mode="streaming"
    telemetry={{ labels: { team: 'data-platform', domain: 'lakehouse' } }}
    parallelism={2}
    stateBackend="rocksdb"
    checkpoint={{ interval: '30s', mode: 'exactly-once' }}
    flinkConfig={{
      's3.endpoint': 'http://seaweedfs.flink-demo.svc:8333',
      's3.path.style.access': 'true',
      's3.access-key': 'admin',
      's3.secret-key': 'admin',
      'state.checkpoints.dir': 's3://flink-state/checkpoints/cdc-to-lakehouse',
      'state.savepoints.dir': 's3://flink-state/savepoints/cdc-to-lakehouse',
    }}
  >
    {iceberg.node}
    <KafkaSource
      topic="dbserver1.inventory.orders"
      schema={OrdersSchema}
      format="debezium-json"
      bootstrapServers="kafka:9092"
      consumerGroup="cdc-lakehouse"
    />
    <IcebergSink
      catalog={iceberg.handle}
      database="inventory"
      table="orders"
      primaryKey={['orderId']}
      formatVersion={2}
      upsertEnabled
    />
  </Pipeline>
);

import { beforeEach, describe, expect, it } from 'vitest'
import {
  type ConstructNode,
  resetNodeIdCounter,
  synthesizeApp,
} from '@flink-reactor/dsl'
import pipeline from '../../pipelines/cdc-to-lakehouse/index.js'

function synth(node: ConstructNode): string {
  const result = synthesizeApp({ name: 'cdc-to-lakehouse', children: [node] })
  return result.pipelines[0].sql.sql
}

describe('cdc-to-lakehouse pipeline', () => {
  beforeEach(() => {
    resetNodeIdCounter()
  })

  it('synthesizes stable SQL', () => {
    const sql = synth(pipeline)

    expect(sql).toMatchSnapshot()

    expect(sql).toMatch(/debezium-json/)
    expect(sql).toMatch(/iceberg/i)
    expect(sql).toMatch(/'format-version'\s*=\s*'2'/i)
  })
})

