export const PageViewsSchema = Schema({
  fields: {
    userId: Field.STRING(),
    pageUrl: Field.STRING(),
    viewTimestamp: Field.TIMESTAMP(3),
  },
  watermark: { column: 'viewTimestamp', expression: 'viewTimestamp - INTERVAL \'5\' SECOND' },
});

import { Schema, Field } from '@flink-reactor/dsl';

// Output shape for the windowed aggregate — not a Kafka source, so it has no
// `sources` entry and lives apart from schemas/page-views.ts.
export const PageViewStatsSchema = Schema({
  fields: {
    pageUrl: Field.STRING(),
    viewCount: Field.BIGINT(),
    windowStart: Field.TIMESTAMP(3),
    windowEnd: Field.TIMESTAMP(3),
  },
});

import { Pipeline, KafkaSource, TumbleWindow, Aggregate, JdbcSink } from '@flink-reactor/dsl';
import { PageViewsSchema } from '@/schemas/page-views';

export default (
  <Pipeline name="page-view-analytics">
    <KafkaSource
      topic="page-views"
      schema={PageViewsSchema}
      bootstrapServers="kafka:9092"
      consumerGroup="analytics"
    />
    <TumbleWindow size="1 MINUTE" on="viewTimestamp" />
    <Aggregate
      groupBy={['pageUrl']}
      select={{
        pageUrl: 'pageUrl',
        viewCount: 'COUNT(*)',
        windowStart: 'window_start',
        windowEnd: 'window_end',
      }}
    />
    <JdbcSink
      table="page_view_stats"
      url="jdbc:postgresql://postgres:5432/analytics"
      upsertMode
      keyFields={['pageUrl', 'windowStart', 'windowEnd']}
    />
  </Pipeline>
);

import { beforeEach, describe, expect, it } from 'vitest'
import {
  type ConstructNode,
  resetNodeIdCounter,
  synthesizeApp,
} from '@flink-reactor/dsl'
import pipeline from '../../pipelines/page-view-analytics/index.js'

function synth(node: ConstructNode): string {
  const result = synthesizeApp({ name: 'page-view-analytics', children: [node] })
  return result.pipelines[0].sql.sql
}

describe('page-view-analytics pipeline', () => {
  beforeEach(() => {
    resetNodeIdCounter()
  })

  it('synthesizes stable SQL', () => {
    const sql = synth(pipeline)

    expect(sql).toMatchSnapshot()

    expect(sql).toMatch(/TUMBLE\(/i)
    expect(sql).toMatch(/GROUP BY/i)
    expect(sql).toMatch(/jdbc/i)
    expect(sql).toMatch(/PRIMARY KEY/i)
  })
})

