{
  "name": "iot-factory",
  "version": "0.1.0",
  "private": true,
  "type": "module",
  "scripts": {
    "dev": "flink-reactor dev",
    "synth": "flink-reactor synth",
    "validate": "flink-reactor validate",
    "test": "vitest run",
    "test:watch": "vitest"
  },
  "dependencies": {
    "@flink-reactor/dsl": "^0.1.0"
  },
