}

import { fileURLToPath } from 'node:url'
import { defineConfig } from 'vitest/config'

export default defineConfig({
  resolve: {
    alias: {
      '@': fileURLToPath(new URL('.', import.meta.url)),
    },
  },
})

import { defineConfig } from '@flink-reactor/dsl'

export default defineConfig({
  flink: { version: '2.3' },

  // Infra services this project depends on. Empty here — `fr cluster up`
  // and `fr sim up` will start only the always-on services (Flink core,
  // SQL gateway, SeaweedFS). Add services as your pipelines need them, e.g.
  // `services: { kafka: {} }` to enable Kafka.
  services: {},

  // `sources` lets `fr schema generate` emit typed `schemas/*.ts` modules by
  // introspecting a live Kafka Schema Registry or Postgres — no hand-writing.
  // Uncomment and point at your source once you add a pipeline, e.g.:
  //   sources: {
  //     orders: { type: 'kafka', topic: 'orders' },
  //     // customers: { type: 'postgres', table: 'public.customers' },
  //   },

  environments: {
    development: {
      cluster: { url: 'http://localhost:8081' },
      dashboard: { mockMode: true },
      pipelines: { '*': { parallelism: 1 } },
    },
    production: {
      cluster: { url: 'https://flink-prod:8081' },
      kubernetes: { namespace: 'flink-prod' },
      pipelines: { '*': { parallelism: 4 } },
    },
  },
})

import { defineConfig } from '@flink-reactor/dsl';

export default defineConfig({
  flink: { version: '2.3' },

  // Kafka for telemetry; Postgres for the JDBC sinks the pipelines write to.
  // `schemaRegistryUrl` is the published host port of the bundled registry —
  // read by `fr schema generate`, not the runtime connectors (the sensor
  // stream is registry-free `format="json"`).
  services: { kafka: { bootstrapServers: 'kafka:9092', schemaRegistryUrl: 'http://localhost:8082' }, postgres: {} },

  // `sources` powers `fr schema generate`: introspect the topic's row schema
  // from the Schema Registry and emit `schemas/sensor-readings.ts`. Only the
  // `<KafkaSource>` input topic is a source here — the device registry reaches
  // the pipeline over JDBC, and the alert/pump topics are outputs, not sources.
  sources: {
    'sensor-readings': { type: 'kafka', topic: 'iot.sensor-readings' },
  },

  environments: {
    minikube: {
      cluster: { url: 'http://localhost:8081' },
      sim: {
        init: {
          kafka: {
            topics: ['iot.maintenance-alerts', 'iot.sensor-readings'],
            catalogs: [{
              name: 'iot',
              tables: [
                {
                  table: 'sensor_readings',
                  topic: 'iot.sensor-readings',
                  format: 'json',
                  columns: {
                    deviceId: 'STRING',
                    sensorType: 'STRING',
                    value: 'DOUBLE',
                    unit: 'STRING',
                    readingTime: 'TIMESTAMP(3)',
                  },
                  watermark: { column: 'readingTime', expression: "readingTime - INTERVAL '5' SECOND" },
                },
                {
                  table: 'device_registry',
                  topic: 'iot.device-registry',
                  format: 'debezium-json',
                  columns: {
                    deviceId: 'STRING',
                    location: 'STRING',
                    firmwareVersion: 'STRING',
                    installDate: 'STRING',
                    thresholdTemp: 'DOUBLE',
                    thresholdVibration: 'DOUBLE',
                    updateTime: 'TIMESTAMP(3)',
                  },
                  primaryKey: ['deviceId'],
                },
              ],
            }],
          },
          jdbc: {
            catalogs: [{
              name: 'flink_sink',
              baseUrl: 'jdbc:postgresql://postgres:5432/',
              defaultDatabase: 'flink_sink',
            }],
          },
        },
      },
      pipelines: { '*': { parallelism: 2 } },
    },
    production: {
      cluster: { url: 'https://flink-prod:8081' },
      kubernetes: { namespace: 'flink-prod' },
      pipelines: { '*': { parallelism: 4 } },
    },
  },
});

import { Schema, Field } from '@flink-reactor/dsl';

export const SensorReadingsSchema = Schema({
  fields: {
    deviceId: Field.STRING(),
    sensorType: Field.STRING(),
    value: Field.DOUBLE(),
    unit: Field.STRING(),
    readingTime: Field.TIMESTAMP(3),
  },
  watermark: { column: 'readingTime', expression: "readingTime - INTERVAL '5' SECOND" },
});

import { Schema, Field } from '@flink-reactor/dsl';

export const DeviceRegistrySchema = Schema({
  fields: {
    deviceId: Field.STRING(),
    location: Field.STRING(),
    firmwareVersion: Field.STRING(),
    installDate: Field.STRING(),
    thresholdTemp: Field.DOUBLE(),
    thresholdVibration: Field.DOUBLE(),
    updateTime: Field.TIMESTAMP(3),
  },
  primaryKey: { columns: ['deviceId'] },
});

import {
  Pipeline, KafkaSource, JdbcSource, KafkaSink, JdbcSink,
  SlideWindow, Aggregate, LookupJoin, Route,
} from '@flink-reactor/dsl';
import { SensorReadingsSchema } from '@/schemas/sensor-readings';
import { DeviceRegistrySchema } from '@/schemas/device-registry';

const readings = KafkaSource({
  topic: "iot.sensor-readings",
  schema: SensorReadingsSchema,
  bootstrapServers: "kafka:9092",
  consumerGroup: "iot-maintenance",
});

// Device registry is a slow-changing dimension — enrich via JDBC lookup
// from the aggregated stats. A Kafka-CDC + event-time TemporalJoin over
// a windowed aggregate hits a Flink-version quirk where window_end/
// window_start lose their rowtime-attribute through the subquery
// boundary (BUG-030); LookupJoin sidesteps it by running on a synthetic
// proctime, which is the natural pattern for dim-enrichment anyway.
const devices = JdbcSource({
  table: "device_registry",
  url: "jdbc:postgresql://postgres:5432/flink_sink",
  schema: DeviceRegistrySchema,
  lookupCache: { type: "lru", maxRows: 10000, ttl: "10min" },
});

const windowed = SlideWindow({ size: "5 MINUTE", slide: "30 SECOND", on: "readingTime", children: readings });

const stats = Aggregate({
  groupBy: ['deviceId', 'sensorType'],
  select: {
    avgValue: 'AVG(`value`)',
    stddevValue: 'STDDEV_POP(`value`)',
    maxValue: 'MAX(`value`)',
    readingCount: 'COUNT(*)',
  },
  children: windowed,
});

const enriched = LookupJoin({
  input: stats,
  dimension: devices,
  on: "deviceId = deviceId",
});

export default (
  <Pipeline
    name="iot-predictive-maintenance"
    mode="streaming"
    parallelism={4}
    stateBackend="rocksdb"
    checkpoint={{ interval: "30s", mode: "exactly-once" }}
    flinkConfig={{
      "state.checkpoints.dir": "s3://flink-state/checkpoints/iot-predictive-maintenance",
      "state.savepoints.dir": "s3://flink-state/savepoints/iot-predictive-maintenance",
      "s3.endpoint": "http://seaweedfs.flink-demo.svc:8333",
      "s3.path.style.access": "true",
    }}
  >
    {readings}
    {enriched}
    <Route>
      <Route.Branch condition="stddevValue > thresholdTemp">
        <KafkaSink topic="iot.maintenance-alerts" bootstrapServers="kafka:9092" />
      </Route.Branch>
      <Route.Default>
        <JdbcSink table="sensor_dashboard" url="jdbc:postgresql://postgres:5432/flink_sink" />
      </Route.Default>
    </Route>
  </Pipeline>
);

import {
  Pipeline, DataGenSource, KafkaSink, StatementSet,
} from '@flink-reactor/dsl';
import { SensorReadingsSchema } from '@/schemas/sensor-readings';
import { DeviceRegistrySchema } from '@/schemas/device-registry';

export default (
  <Pipeline
    name="pump-iot"
    mode="streaming"
    parallelism={2}
    stateBackend="rocksdb"
    checkpoint={{ interval: "60s", mode: "exactly-once" }}
    flinkConfig={{
      "state.checkpoints.dir": "s3://flink-state/checkpoints/pump-iot",
      "state.savepoints.dir": "s3://flink-state/savepoints/pump-iot",
      "s3.endpoint": "http://seaweedfs.flink-demo.svc:8333",
      "s3.path.style.access": "true",
    }}
  >
    <StatementSet>
      <DataGenSource schema={SensorReadingsSchema} rowsPerSecond={5000} />
      <KafkaSink topic="iot.sensor-readings" bootstrapServers="kafka:9092" />

      <DataGenSource schema={DeviceRegistrySchema} rowsPerSecond={20} />
      <KafkaSink topic="iot.device-registry" bootstrapServers="kafka:9092" />
    </StatementSet>
  </Pipeline>
);

import { beforeEach, describe, expect, it } from 'vitest'
import {
  type ConstructNode,
  resetNodeIdCounter,
  synthesizeApp,
} from '@flink-reactor/dsl'
import pipeline from '../../pipelines/iot-predictive-maintenance/index.js'

function synth(node: ConstructNode): string {
  const result = synthesizeApp({ name: 'iot-predictive-maintenance', children: [node] })
  return result.pipelines[0].sql.sql
}

describe('iot-predictive-maintenance pipeline', () => {
  beforeEach(() => {
    resetNodeIdCounter()
  })

  it('synthesizes stable SQL', () => {
    const sql = synth(pipeline)

    expect(sql).toMatchSnapshot()

    expect(sql).toMatch(/HOP\(/i)
    expect(sql).toMatch(/STDDEV_POP\(/i)
    expect(sql).toMatch(/iot\.maintenance-alerts/)
  })
})

import { beforeEach, describe, expect, it } from 'vitest'
import {
  type ConstructNode,
  resetNodeIdCounter,
  synthesizeApp,
} from '@flink-reactor/dsl'
import pipeline from '../../pipelines/pump-iot/index.js'

function synth(node: ConstructNode): string {
  const result = synthesizeApp({ name: 'pump-iot', children: [node] })
  return result.pipelines[0].sql.sql
}

describe('pump-iot pipeline', () => {
  beforeEach(() => {
    resetNodeIdCounter()
  })

  it('synthesizes stable SQL', () => {
    const sql = synth(pipeline)

    expect(sql).toMatchSnapshot()

    expect(sql).toMatch(/INSERT INTO/i)
    expect(sql).toMatch(/datagen/i)
  })
})

