import { fileURLToPath } from 'node:url'
import { defineConfig } from 'vitest/config'

export default defineConfig({
  resolve: {
    alias: {
      '@': fileURLToPath(new URL('.', import.meta.url)),
    },
  },
})

import { defineConfig } from '@flink-reactor/dsl'

export default defineConfig({
  flink: { version: '2.3' },

  // Infra services this project depends on. Empty here — `fr cluster up`
  // and `fr sim up` will start only the always-on services (Flink core,
  // SQL gateway, SeaweedFS). Add services as your pipelines need them, e.g.
  // `services: { kafka: {} }` to enable Kafka.
  services: {},

  // `sources` lets `fr schema generate` emit typed `schemas/*.ts` modules by
  // introspecting a live Kafka Schema Registry or Postgres — no hand-writing.
  // Uncomment and point at your source once you add a pipeline, e.g.:
  //   sources: {
  //     orders: { type: 'kafka', topic: 'orders' },
  //     // customers: { type: 'postgres', table: 'public.customers' },
  //   },

  environments: {
    development: {
      cluster: { url: 'http://localhost:8081' },
      dashboard: { mockMode: true },
      pipelines: { '*': { parallelism: 1 } },
    },
    production: {
      cluster: { url: 'https://flink-prod:8081' },
      kubernetes: { namespace: 'flink-prod' },
      pipelines: { '*': { parallelism: 4 } },
    },
  },
})

import { defineConfig } from '@flink-reactor/dsl';

export default defineConfig({
  flink: { version: '2.3' },

  // Bronze/silver/gold lakehouse analytics on Iceberg, fed from Kafka CDC.
  // `schemaRegistryUrl` is the bundled registry's host port — read by
  // `fr schema generate`, not the runtime connectors (which use debezium-json).
  services: { kafka: { bootstrapServers: 'kafka:9092', schemaRegistryUrl: 'http://localhost:8082' }, iceberg: {} },

  // `sources` powers `fr schema generate`: introspect the `orders.cdc`
  // topic's row schema from the Schema Registry and emit `schemas/medallion.ts`.
  sources: {
    medallion: { type: 'kafka', topic: 'orders.cdc' },
  },

  environments: {
    minikube: {
      cluster: { url: 'http://localhost:8081' },
      sim: {
        init: {
          iceberg: { databases: ['bronze', 'silver', 'gold'] },
          kafka: {
            catalogs: [
              {
                name: 'orders',
                tables: [
                  {
                    table: 'cdc',
                    topic: 'orders.cdc',
                    columns: {
                      orderId: 'STRING',
                      customerId: 'STRING',
                      product: 'STRING',
                      amount: 'DOUBLE',
                      status: 'STRING',
                      updatedAt: 'TIMESTAMP(3)',
                    },
                    format: 'debezium-json',
                    primaryKey: ['orderId'],
                    watermark: { column: 'updatedAt', expression: "updatedAt - INTERVAL '5' SECOND" },
                  },
                ],
              },
            ],
          },
        },
      },
      pipelines: { '*': { parallelism: 4 } },
    },
    production: {
      cluster: { url: 'https://flink-prod:8081' },
      kubernetes: { namespace: 'flink-prod' },
      pipelines: { '*': { parallelism: 4 } },
    },
  },
});

import { Schema, Field } from '@flink-reactor/dsl';

// Bronze: raw CDC events from source systems — the `orders.cdc` topic's row
// schema. Regenerate with `fr schema generate medallion`.
export const MedallionSchema = Schema({
  fields: {
    orderId: Field.STRING(),
    customerId: Field.STRING(),
    product: Field.STRING(),
    amount: Field.DOUBLE(),
    status: Field.STRING(),
    updatedAt: Field.TIMESTAMP(3),
  },
  primaryKey: { columns: ['orderId'] },
  watermark: { column: 'updatedAt', expression: "updatedAt - INTERVAL '5' SECOND" },
});

import { Schema, Field } from '@flink-reactor/dsl';

// Silver: deduplicated, cleaned records
export const OrderCleanSchema = Schema({
  fields: {
    orderId: Field.STRING(),
    customerId: Field.STRING(),
    product: Field.STRING(),
    amount: Field.DOUBLE(),
    status: Field.STRING(),
    updatedAt: Field.TIMESTAMP(3),
  },
  primaryKey: { columns: ['orderId'] },
  watermark: { column: 'updatedAt', expression: "updatedAt - INTERVAL '5' SECOND" },
});

import { Schema, Field } from '@flink-reactor/dsl';

// Gold: aggregated summaries
export const RevenueSummarySchema = Schema({
  fields: {
    product: Field.STRING(),
    totalRevenue: Field.DOUBLE(),
    orderCount: Field.BIGINT(),
    windowStart: Field.TIMESTAMP(3),
    windowEnd: Field.TIMESTAMP(3),
  },
});

