{
  "name": "stock-basics",
  "version": "0.1.0",
  "private": true,
  "type": "module",
  "scripts": {
    "dev": "flink-reactor dev",
    "synth": "flink-reactor synth",
    "validate": "flink-reactor validate",
    "test": "vitest run",
    "test:watch": "vitest"
  },
  "dependencies": {
    "@flink-reactor/dsl": "^0.1.0"
  },
  "devDependencies": {
    "typescript": "^5.7.0",
    "vitest": "^3.0.0"
  }
}

{
  "compilerOptions": {
    "target": "ES2022",
    "module": "ESNext",
    "moduleResolution": "bundler",
    "lib": [
      "ES2022"
    ],
    "strict": true,
    "esModuleInterop": true,
    "skipLibCheck": true,
    "forceConsistentCasingInFileNames": true,
    "resolveJsonModule": true,
    "jsx": "react-jsx",
    "jsxImportSource": "@flink-reactor/dsl",
    "baseUrl": ".",
    "paths": {
      "@/*": [
        "./*"
      ]
    }
  },
  "include": [
    "pipelines/**/*",
    "schemas/**/*",
    "patterns/**/*"
  ]
}

import { fileURLToPath } from 'node:url'
import { defineConfig } from 'vitest/config'

export default defineConfig({
  resolve: {
    alias: {
      '@': fileURLToPath(new URL('.', import.meta.url)),
    },
  },
})

import { defineConfig } from '@flink-reactor/dsl';

export default defineConfig({
  flink: { version: '2.3' },

  // Kafka-only template.
  services: { kafka: { bootstrapServers: 'kafka:9092' } },

  environments: {
    development: {
      cluster: { url: 'http://localhost:8081' },
      dashboard: { mockMode: true },
      pipelines: { '*': { parallelism: 1 } },
    },
    minikube: {
      cluster: { url: 'http://localhost:8081' },
      sim: {
        init: {
          kafka: {
            catalogs: [{
              name: 'basics',
              tables: [
                {
  table: 'words',
  topic: 'words',
  format: 'json',
  rowsPerSecond: 10,
  columns: {
    word: 'STRING',
    frequency: 'INT',
  },
  fields: {
    word: { kind: 'random', length: 8 },
    frequency: { kind: 'random', min: 1, max: 100 },
  },
},
                {
  table: 'orders',
  topic: 'orders',
  format: 'json',
  rowsPerSecond: 10,
  columns: {
    user: 'BIGINT',
    product: 'STRING',
    amount: 'INT',
    ts: 'TIMESTAMP(3)',
  },
  watermark: { column: 'ts', expression: "ts - INTERVAL '5' SECOND" },
  fields: {
    user: { kind: 'random', min: 1, max: 1000 },
    product: { kind: 'random', length: 6 },
    amount: { kind: 'random', min: 1, max: 100 },
  },
},
                {
  table: 'customers',
  topic: 'customers',
  format: 'json',
  rowsPerSecond: 10,
  columns: {
    name: 'STRING',
    date_of_birth: 'DATE',
    street: 'STRING',
    zip_code: 'STRING',
    city: 'STRING',
    gender: 'STRING',
    has_newsletter: 'BOOLEAN',
  },
  fields: {
    name: { kind: 'random', length: 12 },
    street: { kind: 'random', length: 20 },
    zip_code: { kind: 'random', length: 5 },
    city: { kind: 'random', length: 10 },
    gender: { kind: 'random', length: 1 },
  },
},
              ],
            }],
          },
        },
      },
      pipelines: { '*': { parallelism: 1 } },
    },
    production: {
      cluster: { url: 'https://flink-prod:8081' },
      kubernetes: { namespace: 'flink-prod' },
      pipelines: { '*': { parallelism: 2 } },
    },
  },
});

import { Schema, Field } from '@flink-reactor/dsl';

export default Schema({
  fields: {
    word: Field.STRING(),
    frequency: Field.INT(),
  },
});

import { Schema, Field } from '@flink-reactor/dsl';

export default Schema({
  fields: {
    user: Field.BIGINT(),
    product: Field.STRING(),
    amount: Field.INT(),
    ts: Field.TIMESTAMP(3),
  },
  watermark: { column: 'ts', expression: "ts - INTERVAL '5' SECOND" },
});

import { Schema, Field } from '@flink-reactor/dsl';

export default Schema({
  fields: {
    name: Field.STRING(),
    date_of_birth: Field.DATE(),
    street: Field.STRING(),
    zip_code: Field.STRING(),
    city: Field.STRING(),
    gender: Field.STRING(),
    has_newsletter: Field.BOOLEAN(),
  },
});

import {
  Pipeline,
  RawSQL,
  Aggregate,
  GenericSink,
} from '@flink-reactor/dsl';
import WordSchema from '@/schemas/word';

export default (
  <Pipeline name="wordcount-sql">
    <RawSQL
      sql={`SELECT \`word\`, \`frequency\` FROM (VALUES
        ('Hello', 1),
        ('World', 2),
        ('Hello', 3),
        ('World', 4),
        ('Hello', 5)
      ) AS T(\`word\`, \`frequency\`)`}
      outputSchema={WordSchema}
    />
    <Aggregate
      groupBy={['word']}
      select={{
        word: '\`word\`',
        frequency: 'SUM(\`frequency\`)',
      }}
    />
    <GenericSink connector="print" />
  </Pipeline>
);

import {
  Pipeline,
  DataGenSource,
  Filter,
  Map,
  GenericSink,
} from '@flink-reactor/dsl';
import CustomerSchema from '@/schemas/customer';

export default (
  <Pipeline name="getting-started">
    <DataGenSource schema={CustomerSchema} rowsPerSecond={5} />
    {/* JSX attributes are not JS strings, so column references in
        condition= are written without backticks; date_of_birth and
        has_newsletter are not SQL-reserved identifiers. */}
    <Filter
      condition="TIMESTAMPDIFF(YEAR, date_of_birth, CURRENT_DATE) >= 18 AND has_newsletter = TRUE"
    />
    <Map
      select={{
        name: 'name',
        normalized_address: "UPPER(REGEXP_REPLACE(street, ' +', ' '))",
        city: 'city',
      }}
    />
    <GenericSink connector="print" />
  </Pipeline>
);

import {
  Pipeline,
  DataGenSource,
  Filter,
  Union,
  GenericSink,
} from '@flink-reactor/dsl';
import OrderSchema from '@/schemas/order';

const ordersA = DataGenSource({
  schema: OrderSchema,
  name: 'orders_a',
  rowsPerSecond: 5,
});

const ordersB = DataGenSource({
  schema: OrderSchema,
  name: 'orders_b',
  rowsPerSecond: 5,
});

const filteredA = Filter({
  condition: '\`amount\` > 2',
  children: ordersA,
});

const filteredB = Filter({
  condition: "\`product\` LIKE '%Rubber%'",
  children: ordersB,
});

export default (
  <Pipeline name="stream-sql-union">
    <Union>
      {filteredA}
      {filteredB}
    </Union>
